template <typename T>
__device__ inline void atomicAddCustom(T* addr, T val);

template <>
__device__ inline void atomicAddCustom<float>(float* addr, float val) {
  atomicAdd(addr, val);
}

template <>
__device__ inline void atomicAddCustom<int>(int* addr, int val) {
  atomicAdd(addr, val);
}

template <>
__device__ inline void atomicAddCustom<double>(double* addr, double val) {
#if __CUDA_ARCH__ >= 600
  atomicAdd(addr, val);
#else
  unsigned long long int* address_as_ull =
      reinterpret_cast<unsigned long long int*>(addr);
  unsigned long long int old = *address_as_ull, assumed;
  do {
    assumed = old;
    old = atomicCAS(address_as_ull, assumed,
                    __double_as_longlong(val + __longlong_as_double(assumed)));
  } while (assumed != old);
#endif
}

