template <typename Element>
__global__ void reduce_kernel(const Element* partial, size_t n, Element* out) {
  extern __shared__ unsigned char smem[];
  Element* sdata = reinterpret_cast<Element*>(smem);

  unsigned int tid = threadIdx.x;
  size_t idx = static_cast<size_t>(blockIdx.x) * blockDim.x + tid;
  size_t stride = static_cast<size_t>(gridDim.x) * blockDim.x;

  Element sum = 0;
  for (size_t i = idx; i < n; i += stride) {
    sum += partial[i];
  }

  sdata[tid] = sum;
  __syncthreads();

  for (unsigned int s = blockDim.x / 2; s > 0; s >>= 1) {
    if (tid < s) sdata[tid] += sdata[tid + s];
    __syncthreads();
  }

  if (tid == 0) {
    atomicAddCustom(out, sdata[0]);
  }
}

template <typename Element>
__global__ void write_first_kernel(Element* src, const Element* value) {
  if (blockIdx.x == 0 && threadIdx.x == 0) {
    *src = *value;
  }
}

template <typename Element, unsigned int compute_iterations>
size_t bench(size_t len, const Element seed1, const Element seed2, Element* src) {
  (void)seed1;
  (void)seed2;

  constexpr size_t static_chunk_size = 4096;
  if (len == 0) return 0;

  const size_t num_chunks = len / static_chunk_size;
  if (num_chunks == 0) return len;

  Element* d_partial = nullptr;
  Element* d_sum = nullptr;

  CUDA_SAFE_CALL(cudaMalloc(&d_partial, num_chunks * sizeof(Element)));
  CUDA_SAFE_CALL(cudaMalloc(&d_sum, sizeof(Element)));
  CUDA_SAFE_CALL(cudaMemset(d_sum, 0, sizeof(Element)));

  const int block_size = 128;
  const int grid_size =
      static_cast<int>((num_chunks + block_size - 1) / block_size);

  bench_block_kernel<Element, compute_iterations, static_chunk_size>
      <<<grid_size, block_size>>>(src, d_partial, num_chunks);
  CUDA_SAFE_CALL(cudaGetLastError());

  const int red_block = 256;
  int red_grid = static_cast<int>((num_chunks + red_block - 1) / red_block);
  if (red_grid > 1024) red_grid = 1024;
  if (red_grid < 1) red_grid = 1;

  reduce_kernel<Element><<<red_grid, red_block, red_block * sizeof(Element)>>>(
      d_partial, num_chunks, d_sum);
  CUDA_SAFE_CALL(cudaGetLastError());

  write_first_kernel<Element><<<1, 1>>>(src, d_sum);
  CUDA_SAFE_CALL(cudaGetLastError());

  CUDA_SAFE_CALL(cudaDeviceSynchronize());

  CUDA_SAFE_CALL(cudaFree(d_sum));
  CUDA_SAFE_CALL(cudaFree(d_partial));

  return len;
}

